## Step 1: Config

```go
// generator/config.go

package generator

type Config struct {
    // Array dimensions
    Rows int
    Cols int

    // Cell properties (SKY130 placeholder)
    CellName   string
    CellWidth  float64 // microns
    CellHeight float64 // microns

    // Grid (SKY130 HD)
    DBU int // Database units per micron (1000)

    // Design
    DesignName string
}

func DefaultConfig() *Config {
    return &Config{
        Rows:       4,
        Cols:       4,
        CellName:   "fecim_bitcell",
        CellWidth:  0.46, // 1 x-pitch
        CellHeight: 2.72, // 1 standard row
        DBU:        1000,
        DesignName: "fecim_crossbar_4x4",
    }
}

func (c *Config) DieWidth() float64 {
    return float64(c.Cols) * c.CellWidth
}

func (c *Config) DieHeight() float64 {
    return float64(c.Rows) * c.CellHeight
}

func (c *Config) ToDBU(microns float64) int {
    return int(microns * float64(c.DBU))
}
```

