## Step 2: DEF Generator

```go
// generator/def.go

package generator

import (
    "fmt"
    "io"
    "text/template"
)

type Cell struct {
    Name   string
    X      int // DBU
    Y      int // DBU
    Orient string
}

type Pin struct {
    Name      string
    Direction string // INPUT or OUTPUT
    Layer     string
    X         int // DBU
    Y         int // DBU
}

type DEFData struct {
    Version    string
    DesignName string
    DBU        int
    DieAreaX   int
    DieAreaY   int
    Cells      []Cell
    Pins       []Pin
    CellName   string
}

func GenerateDEF(cfg *Config, w io.Writer) error {
    data := DEFData{
        Version:    "5.8",
        DesignName: cfg.DesignName,
        DBU:        cfg.DBU,
        DieAreaX:   cfg.ToDBU(cfg.DieWidth()),
        DieAreaY:   cfg.ToDBU(cfg.DieHeight()),
        CellName:   cfg.CellName,
    }

    // Generate cells
    for row := 0; row < cfg.Rows; row++ {
        for col := 0; col < cfg.Cols; col++ {
            // Alternate orientation for abutment
            orient := "N"
            if col%2 == 1 {
                orient = "FN"
            }

            data.Cells = append(data.Cells, Cell{
                Name:   fmt.Sprintf("cell_%d_%d", row, col),
                X:      cfg.ToDBU(float64(col) * cfg.CellWidth),
                Y:      cfg.ToDBU(float64(row) * cfg.CellHeight),
                Orient: orient,
            })
        }
    }

    // Generate wordline pins (left edge)
    for row := 0; row < cfg.Rows; row++ {
        y := cfg.ToDBU(float64(row)*cfg.CellHeight + cfg.CellHeight/2)
        data.Pins = append(data.Pins, Pin{
            Name:      fmt.Sprintf("WL[%d]", row),
            Direction: "INPUT",
            Layer:     "met1",
            X:         0,
            Y:         y,
        })
    }

    // Generate bitline pins (bottom edge)
    for col := 0; col < cfg.Cols; col++ {
        x := cfg.ToDBU(float64(col)*cfg.CellWidth + cfg.CellWidth/2)
        data.Pins = append(data.Pins, Pin{
            Name:      fmt.Sprintf("BL[%d]", col),
            Direction: "OUTPUT",
            Layer:     "met2",
            X:         x,
            Y:         0,
        })
    }

    return defTemplate.Execute(w, data)
}

var defTemplate = template.Must(template.New("def").Parse(`VERSION {{ .Version }} ;
DIVIDERCHAR "/" ;
BUSBITCHARS "[]" ;
DESIGN {{ .DesignName }} ;
UNITS DISTANCE MICRONS {{ .DBU }} ;

DIEAREA ( 0 0 ) ( {{ .DieAreaX }} {{ .DieAreaY }} ) ;

COMPONENTS {{ len .Cells }} ;
{{- range .Cells }}
  - {{ .Name }} {{ $.CellName }} + FIXED ( {{ .X }} {{ .Y }} ) {{ .Orient }} ;
{{- end }}
END COMPONENTS

PINS {{ len .Pins }} ;
{{- range .Pins }}
  - {{ .Name }} + NET {{ .Name }} + DIRECTION {{ .Direction }} + LAYER {{ .Layer }} ( {{ .X }} {{ .Y }} ) ;
{{- end }}
END PINS

END DESIGN
`))
```

