// generator/verilog.go

package generator

import (
    "io"
    "text/template"
)

type VerilogData struct {
    ModuleName string
    CellName   string
    Rows       int
    Cols       int
    Cells      []CellInstance
}

type CellInstance struct {
    Name string
    Row  int
    Col  int
}

func GenerateVerilog(cfg *Config, w io.Writer) error {
    data := VerilogData{
        ModuleName: cfg.DesignName,
        CellName:   cfg.CellName,
        Rows:       cfg.Rows,
        Cols:       cfg.Cols,
    }

    for row := 0; row < cfg.Rows; row++ {
        for col := 0; col < cfg.Cols; col++ {
            data.Cells = append(data.Cells, CellInstance{
                Name: fmt.Sprintf("cell_%d_%d", row, col),
                Row:  row,
                Col:  col,
            })
        }
    }

    return verilogTemplate.Execute(w, data)
}

var verilogTemplate = template.Must(template.New("verilog").Parse(`// Auto-generated by FeCIM Lattice Generator
