// generator/lib.go

package generator

import (
    "io"
    "text/template"
    "time"
)

type LibData struct {
    CellName  string
    Timestamp string
}

func GenerateLib(cfg *Config, w io.Writer) error {
    data := LibData{
        CellName:  cfg.CellName,
        Timestamp: time.Now().Format(time.RFC3339),
    }

    return libTemplate.Execute(w, data)
}

var libTemplate = template.Must(template.New("lib").Parse(`
