## Step 5: CLI Main

```go
// cmd/fecim-gen/main.go

package main

import (
    "flag"
    "fmt"
    "os"
    "path/filepath"

    "fecim-eda/generator"
)

func main() {
    // Flags
    rows := flag.Int("rows", 4, "Number of rows")
    cols := flag.Int("cols", 4, "Number of columns")
    outDir := flag.String("out", "output", "Output directory")
    name := flag.String("name", "fecim_crossbar", "Design name")

    flag.Parse()

    // Create config
    cfg := generator.DefaultConfig()
    cfg.Rows = *rows
    cfg.Cols = *cols
    cfg.DesignName = fmt.Sprintf("%s_%dx%d", *name, *rows, *cols)

    // Create output directory
    if err := os.MkdirAll(*outDir, 0755); err != nil {
        fmt.Fprintf(os.Stderr, "Error creating output dir: %v\n", err)
        os.Exit(1)
    }

    // Generate DEF
    defPath := filepath.Join(*outDir, cfg.DesignName+".def")
    defFile, err := os.Create(defPath)
    if err != nil {
        fmt.Fprintf(os.Stderr, "Error creating DEF file: %v\n", err)
        os.Exit(1)
    }
    defer defFile.Close()

    if err := generator.GenerateDEF(cfg, defFile); err != nil {
        fmt.Fprintf(os.Stderr, "Error generating DEF: %v\n", err)
        os.Exit(1)
    }
    fmt.Printf("✅ Generated: %s\n", defPath)

    // Generate Verilog
    vPath := filepath.Join(*outDir, cfg.DesignName+".v")
    vFile, err := os.Create(vPath)
    if err != nil {
        fmt.Fprintf(os.Stderr, "Error creating Verilog file: %v\n", err)
        os.Exit(1)
    }
    defer vFile.Close()

    if err := generator.GenerateVerilog(cfg, vFile); err != nil {
        fmt.Fprintf(os.Stderr, "Error generating Verilog: %v\n", err)
        os.Exit(1)
    }
    fmt.Printf("✅ Generated: %s\n", vPath)

    // Generate Liberty
    libPath := filepath.Join(*outDir, cfg.CellName+".lib")
    libFile, err := os.Create(libPath)
    if err != nil {
        fmt.Fprintf(os.Stderr, "Error creating Liberty file: %v\n", err)
        os.Exit(1)
    }
    defer libFile.Close()

    if err := generator.GenerateLib(cfg, libFile); err != nil {
        fmt.Fprintf(os.Stderr, "Error generating Liberty: %v\n", err)
        os.Exit(1)
    }
    fmt.Printf("✅ Generated: %s\n", libPath)

    // Summary
    fmt.Println()
    fmt.Println("═══════════════════════════════════════")
    fmt.Printf("FeCIM Lattice: %d×%d = %d cells\n", cfg.Rows, cfg.Cols, cfg.Rows*cfg.Cols)
    fmt.Printf("Die Area: %.2f μm × %.2f μm\n", cfg.DieWidth(), cfg.DieHeight())
    fmt.Printf("Pins: %d WL + %d BL = %d total\n", cfg.Rows, cfg.Cols, cfg.Rows+cfg.Cols)
    fmt.Println("═══════════════════════════════════════")
}
```

